def add_school_perspectives(file_path):
    """为概念添加学派观点"""
    with open(file_path, 'r', encoding='utf-8') as f:
        content = f.read()
    
    # 对每个需要补充的概念进行处理
    for concept_id, perspectives in PERSPECTIVES_DATA.items():
        # 查找该概念的定义
        pattern = rf"(\s*id:\s*'{re.escape(concept_id)}'.*?)(,\s*\n\s*\}})"
        
        def replace_func(match):
            concept_block = match.group(1)
            closing = match.group(2)
            
            # 检查是否已有schoolPerspectives
            if 'schoolPerspectives:' in concept_block:
                return match.group(0)
            
            # 构建schoolPerspectives对象
            perspectives_str = ',\n    '.join([
                f"'{school}': '{perspective}'"
                for school, perspective in perspectives.items()
            ])
            
            return f"{concept_block},\n    schoolPerspectives: {{\n      {perspectives_str}\n    }}{closing}"
        
        content = re.sub(pattern, replace_func, content, flags=re.DOTALL)
    
    # 写回文件
    with open(file_path, 'w', encoding='utf-8') as f:
        f.write(content)
    
    print(f"已为 {len(PERSPECTIVES_DATA)} 个概念添加学派观点")

if __name__ == '__main__':
    add_school_perspectives('/home/ubuntu/psychoanalysis_network/psychoanalysis_data.ts')
    print("补充完成！")
